  form.reset();['id','deliveryMode','name','grade','days','startTime','capacity'].forEach(key=>{if(form.elements[key])form.elements[key].value=item[key]||(key==='deliveryMode'?'center':'');});form.elements.active.checked=item.active!==false;document.getElementById('scheduleEditorTitle').textContent=`تعديل: ${item.name||'الموعد'}`;modal.hidden=false;form.elements.name.focus();
