function reviewContentRow(item,kind){return `<article class="card admin-content-row"><span class="admin-content-icon" data-icon="${kind==='question'?'help-circle':'book-open'}"></span><div><b>${safe(item.title||'بدون عنوان')}</b><small>${safe(item.grade||'كل الصفوف')} · ${reviewTargetLabel(item)}${item.fileUrl?' · ملف مرفق':''}</small></div>${item.fileUrl?`<a class="small-btn" href="${safe(item.fileUrl)}" target="_blank" rel="noopener">فتح</a>`:''}<button class="small-btn primary" type="button" onclick="editReviewContent('${kind}','${safe(item.id)}')">تعديل</button><button class="small-btn danger" type="button" onclick="deleteItem('${kind==='question'?'questions':'materials'}','${safe(item.id)}')">حذف</button></article>`;}
