window.editReviewContent=function(kind,id){
  const collection=kind==='question'?'questions':'materials',item=(adminData[collection]||[]).find(row=>String(row.id)===String(id));if(!item)return aToast('المحتوى غير موجود');openReviewContentEditor(kind);const form=document.getElementById('reviewContentForm');['id','title','deliveryMode','grade','linkUrl','content','answer'].forEach(key=>{if(form.elements[key])form.elements[key].value=item[key]||(key==='deliveryMode'?'all':'');});document.getElementById('reviewContentTitle').textContent=`تعديل: ${item.title||'المحتوى'}`;
};
async function saveReviewContent(event){
  event.preventDefault();const form=event.currentTarget,values=Object.fromEntries(new FormData(form).entries()),file=form.file.files[0],button=form.querySelector('[type=submit]'),collection=values.contentKind==='question'?'questions':'materials',existing=(adminData[collection]||[]).find(item=>String(item.id)===String(values.id));delete values.file;delete values.contentKind;
  if(!file&&!values.content.trim()&&!values.linkUrl&&!existing?.fileUrl)return aToast('اكتب محتوى أو اختر ملفًا أو أضف رابطًا');if(file&&file.size>15*1024*1024)return aToast('الحد الأقصى للملف 15MB');values.id=values.id||(collection==='questions'?`q-${Date.now()}`:`mat-${Date.now()}`);if(collection==='materials')values.contentType='review';button.disabled=true;
  try{if(file){const uploaded=await window.MFCloud.uploadAttachment(file,collection==='questions'?'question-bank':'reviews');values.fileUrl=uploaded.url;values.fileName=file.name;values.fileType=file.type;}const index=adminData[collection].findIndex(item=>String(item.id)===String(values.id));if(index>=0)adminData[collection][index]={...adminData[collection][index],...values};else adminData[collection].push(values);await saveAdminDataNow();aToast(index>=0?'تم تعديل المحتوى':'تم نشر المحتوى');closeReviewContentEditor();renderMaterialsProfessionalV62();}
  catch(error){aToast(adminActionErrorMessage(error,'تعذر حفظ المحتوى.'));}
  finally{button.disabled=false;}
}

