function examTargetLabel(item){return item.deliveryMode==='online'?'أونلاين':item.deliveryMode==='center'?'سنتر':'السنتر والأونلاين';}
function examQuestionType(question){const opts=question?.options||[];return opts.length&&normalizeText(opts.join(' '))===normalizeText('صح غلط')?'truefalse':opts.length?'mcq':'essay';}
function addExamQuestionDataV63(question={}){
  window.addMixedQuestion();const card=document.getElementById('mixedQuestions')?.lastElementChild;if(!card)return;
  const type=examQuestionType(question),select=card.querySelector('[data-question-type]');select.value=type;changeQuestionType(select);card.querySelector('[data-question-text]').value=question.question||question.content||'';
  if(type==='essay')return;const options=type==='truefalse'?['صح','غلط']:(question.options||[]).slice(0,4);card.querySelectorAll('[data-question-option]').forEach((input,index)=>input.value=options[index]||'');
  const labels=question.optionLabels||['أ','ب','ج','د'],answer=String(question.answer||''),answerIndex=options.findIndex(option=>normalizeText(option)===normalizeText(answer)),correct=answerIndex>=0?(labels[answerIndex]||['أ','ب','ج','د'][answerIndex]):answer;card.querySelector('[data-correct-answer]').value=correct||'أ';
}
function examGroupsOptionsV63(selected='',mode='all',grade='كل الصفوف'){return `<option value="كل المجموعات">كل المجموعات</option>${(adminData.groups||[]).filter(item=>item.active!==false&&(mode==='all'||scheduleMode(item)===mode)&&(grade==='كل الصفوف'||item.grade===grade)).map(item=>`<option value="${safe(item.name)}" ${item.name===selected?'selected':''}>${safe(item.name)} — ${safe(item.grade||'')}</option>`).join('')}`;}
function refreshTargetGroupsV63(form,selected=''){if(!form?.elements.group)return;const current=selected||form.elements.group.value||'كل المجموعات',mode=form.elements.deliveryMode?.value||'all',grade=form.elements.grade?.value||'كل الصفوف';form.elements.group.innerHTML=examGroupsOptionsV63(current,mode,grade);form.elements.group.value=[...form.elements.group.options].some(option=>option.value===current)?current:'كل المجموعات';}
function examListRowV63(ex){const state=ex.active===false?'مسودة':(ex.openAt&&new Date(ex.openAt)>new Date()?'مجدول':'منشور');return `<article class="card admin-content-row mobile-manager-row exam-manager-row"><span class="admin-content-icon" data-icon="clipboard"></span><div class="manager-row-copy"><b>${safe(ex.title||'امتحان')}</b><small>${examTargetLabel(ex)} · ${safe(ex.grade||'كل الصفوف')} · ${safe(ex.group||'كل المجموعات')} · ${safe(ex.questionCount||parseExamQuestions(ex.text||'').length)} سؤال</small></div><span class="badge manager-row-status ${ex.active===false?'warn':'good'}">${state}</span><div class="mobile-manager-actions"><button class="small-btn primary" type="button" onclick="openExamEditorV63('${safe(ex.id)}')">تعديل</button><button class="small-btn ghost" type="button" onclick="duplicateExamV63('${safe(ex.id)}')">نسخ</button><button class="small-btn ghost" type="button" onclick="toggleExamV63('${safe(ex.id)}')">${ex.active===false?'نشر':'إيقاف'}</button><button class="small-btn danger" type="button" onclick="deleteItem('exams','${safe(ex.id)}')">حذف</button></div></article>`;}
function renderExamsManagerV63(){
  fresh();const attempts=(adminData.examAttempts||[]).slice().reverse(),pending=attempts.filter(item=>item.needsManualReview||item.status==='pending_manual'),bank=(adminData.questions||[]).filter(item=>item.content&&!item.fileUrl);
  content(`<div class="section-head mobile-manager-head"><div><span class="kicker"><span data-icon="clipboard"></span> الامتحانات</span><h2 class="section-title">إنشاء وتعديل الامتحانات</h2><p class="section-desc">أنشئ الامتحان كمسودة، رتب الأسئلة، ثم انشره للسنتر أو الأونلاين في الوقت المناسب.</p></div><button class="btn primary" type="button" onclick="openExamEditorV63()">+ امتحان جديد</button></div><div class="admin-clean-list mobile-manager-list">${(adminData.exams||[]).map(examListRowV63).join('')||'<div class="card empty-state"><h3>لا توجد امتحانات بعد</h3><p>ابدأ بإنشاء امتحان ثم أضف أسئلته.</p></div>'}</div><details class="card admin-collapsible" ${pending.length?'open':''}><summary>محاولات تحتاج تصحيح <span class="badge warn">${pending.length}</span></summary>${pending.map(examAttemptRowHTML).join('')||'<p>لا توجد محاولات معلقة.</p>'}</details><details class="card admin-collapsible"><summary>كل النتائج والمحاولات</summary>${attempts.map(examAttemptRowHTML).join('')||'<p>لا توجد محاولات.</p>'}</details>
  <div class="admin-form-modal wide-modal mobile-manager-modal mobile-exam-editor" id="examEditorV63" hidden><div class="admin-form-modal-card card"><div class="profile-top"><div><span class="kicker">منشئ الامتحان</span><h2 id="examEditorTitleV63">امتحان جديد</h2></div><button class="small-btn danger" type="button" onclick="closeExamEditorV63()">إغلاق</button></div><form id="examFormV63" class="mobile-manager-form"><input type="hidden" name="id"><section class="exam-builder-step"><h3>1. إعداد الامتحان</h3><div class="exam-meta-grid"><div class="field"><label>اسم الامتحان</label><input name="title" required></div><div class="field"><label>نوع الدراسة</label><select name="deliveryMode"><option value="all">السنتر والأونلاين</option><option value="center">السنتر فقط</option><option value="online">الأونلاين فقط</option></select></div><div class="field"><label>الصف</label><select name="grade"><option>كل الصفوف</option>${GRADES.map(g=>`<option>${safe(g)}</option>`).join('')}</select></div><div class="field"><label>المجموعة</label><select name="group">${examGroupsOptionsV63()}</select></div><div class="field"><label>المدة بالدقائق</label><input name="duration" type="number" min="1" max="300" value="20" required></div><div class="field"><label>يفتح في</label><input name="openAt" type="datetime-local"></div><div class="field"><label>يغلق في</label><input name="closeAt" type="datetime-local"></div></div><div class="field"><label>تعليمات الامتحان</label><textarea name="instructions"></textarea></div><label class="exam-pdf-upload"><span><b>PDF اختياري</b><small>يظل الملف القديم عند التعديل إذا لم تختر ملفًا جديدًا.</small></span><input name="pdfFile" type="file" accept="application/pdf"></label><div class="option-grid"><label class="option-card"><input name="active" type="checkbox"> نشر الامتحان الآن</label><label class="option-card"><input name="allowRetake" type="checkbox"> السماح بإعادة الامتحان</label></div></section><section class="exam-builder-step"><div class="exam-builder-title"><div><h3>2. أسئلة الامتحان</h3><small>اختياري، صح وغلط، ومقالي في امتحان واحد.</small></div></div>${bank.length?`<details class="question-bank-import"><summary>إضافة من بنك الأسئلة <span class="badge">${bank.length}</span></summary><div class="question-bank-picks">${bank.map(item=>`<label><input type="checkbox" value="${safe(item.id)}"> <span><b>${safe(item.title)}</b><small>${safe(item.grade||'كل الصفوف')}</small></span></label>`).join('')}</div><button class="small-btn primary" type="button" onclick="importBankQuestionsV63()">إضافة المحدد</button></details>`:''}<div id="mixedQuestions"></div><button class="btn ghost exam-add-question-bottom" type="button" onclick="addMixedQuestion()"><span data-icon="plus"></span> إضافة سؤال تحت آخر سؤال</button></section><button class="btn primary full-width" type="submit">حفظ الامتحان</button></form></div></div>`);
  const form=document.getElementById('examFormV63');form.addEventListener('submit',saveExamV63);form.elements.deliveryMode.addEventListener('change',()=>refreshTargetGroupsV63(form));form.elements.grade.addEventListener('change',()=>refreshTargetGroupsV63(form));hydrateIcons();
}
window.closeExamEditorV63=function(){const modal=document.getElementById('examEditorV63');if(modal)modal.hidden=true;};
window.openExamEditorV63=function(id=''){const modal=document.getElementById('examEditorV63'),form=document.getElementById('examFormV63'),list=document.getElementById('mixedQuestions');if(!modal||!form||!list)return;form.reset();list.innerHTML='';const item=(adminData.exams||[]).find(row=>String(row.id)===String(id));form.elements.id.value=item?.id||'';form.elements.duration.value=item?.duration||20;form.elements.active.checked=item?item.active!==false:false;form.elements.allowRetake.checked=item?.allowRetake===true;['title','deliveryMode','grade','openAt','closeAt','instructions'].forEach(key=>{if(form.elements[key])form.elements[key].value=item?.[key]||(key==='deliveryMode'?'all':key==='grade'?'كل الصفوف':'');});refreshTargetGroupsV63(form,item?.group||'كل المجموعات');(item?parseExamQuestions(item.text||''):[{}]).forEach(addExamQuestionDataV63);document.getElementById('examEditorTitleV63').textContent=item?`تعديل: ${item.title}`:'امتحان جديد';modal.hidden=false;form.elements.title.focus();};
window.importBankQuestionsV63=function(){const chosen=[...document.querySelectorAll('.question-bank-picks input:checked')].map(input=>input.value);if(!chosen.length)return aToast('حدد سؤالًا واحدًا على الأقل');chosen.forEach(id=>{const item=(adminData.questions||[]).find(row=>String(row.id)===String(id));if(!item)return;const parsed=parseExamQuestions(item.content||'');(parsed.length?parsed:[{question:item.content,answer:item.answer||''}]).forEach(addExamQuestionDataV63);});aToast(`تمت إضافة ${chosen.length} من بنك الأسئلة`);};
async function saveExamV63(event){event.preventDefault();const form=event.currentTarget,cards=[...document.querySelectorAll('#mixedQuestions [data-exam-question]')],text=serializeMixedQuestions(),values=Object.fromEntries(new FormData(form).entries()),file=form.pdfFile.files[0],button=form.querySelector('[type=submit]'),existing=(adminData.exams||[]).find(item=>String(item.id)===String(values.id)),before=existing?{...existing}:null;delete values.pdfFile;if(!cards.length||!text||text.split(/\n\s*\n/).length!==cards.length)return aToast('أكمل بيانات وإجابة كل سؤال');if(values.openAt&&values.closeAt&&new Date(values.closeAt)<=new Date(values.openAt))return aToast('موعد الغلق يجب أن يكون بعد موعد الفتح');values.id=values.id||`ex-${Date.now()}`;values.text=text;values.active=form.active.checked;values.allowRetake=form.allowRetake.checked;values.questionCount=cards.length;values.updatedAt=new Date().toISOString();button.disabled=true;try{if(file){const uploaded=await window.MFCloud.uploadAttachment(file,'exam-pdf');values.pdfUrl=uploaded.url;values.pdfName=file.name;}const index=adminData.exams.findIndex(item=>String(item.id)===String(values.id));if(index>=0)adminData.exams[index]={...adminData.exams[index],...values};else adminData.exams.push({...values,createdAt:new Date().toISOString()});await saveAdminDataNow();aToast(index>=0?'تم تعديل الامتحان':'تم حفظ الامتحان');closeExamEditorV63();renderExamsManagerV63();}catch(error){if(before){const index=adminData.exams.findIndex(item=>String(item.id)===String(values.id));if(index>=0)adminData.exams[index]=before;}else adminData.exams=adminData.exams.filter(item=>String(item.id)!==String(values.id));aToast(adminActionErrorMessage(error,'تعذر حفظ الامتحان.'));}finally{button.disabled=false;}}
window.duplicateExamV63=async function(id){const item=(adminData.exams||[]).find(row=>String(row.id)===String(id));if(!item)return;const copy={...item,id:`ex-${Date.now()}`,title:`نسخة من ${item.title||'الامتحان'}`,active:false,createdAt:new Date().toISOString()};adminData.exams.push(copy);try{await saveAdminDataNow();aToast('تم إنشاء نسخة كمسودة');renderExamsManagerV63();}catch(error){adminData.exams=adminData.exams.filter(row=>row!==copy);aToast(adminActionErrorMessage(error,'تعذر نسخ الامتحان.'));}};
window.toggleExamV63=async function(id){const item=(adminData.exams||[]).find(row=>String(row.id)===String(id));if(!item)return;const before=item.active;item.active=item.active===false;try{await saveAdminDataNow();aToast(item.active?'تم نشر الامتحان':'تم تحويل الامتحان لمسودة');renderExamsManagerV63();}catch(error){item.active=before;aToast(adminActionErrorMessage(error,'تعذر تغيير حالة الامتحان.'));}};

function assignmentSubmissionsV63(assignmentId){return (adminData.students||[]).flatMap(student=>(student.homeworks||[]).filter(item=>String(item.assignmentId||'')===String(assignmentId)).map(item=>({...item,studentCode:stCode(student),studentName:stName(student)})));}
function assignmentRowV63(item){const count=assignmentSubmissionsV63(item.id).length;return `<article class="card admin-content-row mobile-manager-row assignment-manager-row"><span class="admin-content-icon" data-icon="file-text"></span><div class="manager-row-copy"><b>${safe(item.title||'واجب')}</b><small>${examTargetLabel(item)} · ${safe(item.grade||'كل الصفوف')} · ${safe(item.group||'كل المجموعات')} · ${safe(item.dueDate||'بدون موعد')}</small></div><span class="badge manager-row-status ${item.active===false?'warn':'good'}">${item.active===false?'مسودة':'منشور'}</span><div class="mobile-manager-actions"><button class="small-btn ghost" onclick="showAssignmentSubmissionsV63('${safe(item.id)}')">التسليمات (${count})</button><button class="small-btn primary" onclick="openAssignmentEditorV63('${safe(item.id)}')">تعديل</button><button class="small-btn ghost" onclick="toggleAssignmentV63('${safe(item.id)}')">${item.active===false?'نشر':'إيقاف'}</button><button class="small-btn danger" onclick="deleteItem('assignments','${safe(item.id)}')">حذف</button></div></article>`;}
function renderAssignmentsManagerV63(){fresh();content(`<div class="section-head mobile-manager-head"><div><span class="kicker"><span data-icon="file-text"></span> الواجبات</span><h2 class="section-title">الواجبات والتسليمات</h2><p class="section-desc">حدد النوع والصف والمجموعة، ثم تابع ملفات الطلاب وصححها من نفس الصفحة.</p></div><button class="btn primary" onclick="openAssignmentEditorV63()">+ واجب جديد</button></div><div class="admin-clean-list mobile-manager-list">${(adminData.assignments||[]).map(assignmentRowV63).join('')||'<div class="card empty-state"><h3>لا توجد واجبات</h3></div>'}</div><div class="admin-form-modal mobile-manager-modal" id="assignmentEditorV63" hidden><div class="admin-form-modal-card card"><div class="profile-top"><h2 id="assignmentTitleV63">واجب جديد</h2><button class="small-btn danger" type="button" onclick="closeAssignmentEditorV63()">إغلاق</button></div><form id="assignmentFormV63" class="admin-form-grid mobile-manager-form"><input type="hidden" name="id"><div class="field"><label>عنوان الواجب</label><input name="title" required></div><div class="field"><label>نوع الدراسة</label><select name="deliveryMode"><option value="all">السنتر والأونلاين</option><option value="center">السنتر فقط</option><option value="online">الأونلاين فقط</option></select></div><div class="field"><label>الصف</label><select name="grade"><option>كل الصفوف</option>${GRADES.map(g=>`<option>${safe(g)}</option>`).join('')}</select></div><div class="field"><label>المجموعة</label><select name="group">${examGroupsOptionsV63()}</select></div><div class="field"><label>آخر موعد</label><input name="dueDate" type="date"></div><div class="field full-span"><label>التعليمات</label><textarea name="notes"></textarea></div><label class="admin-file-drop full-span"><b>صورة أو PDF اختياري</b><input name="file" type="file" accept="image/*,application/pdf"></label><label class="option-card full-span"><input name="active" type="checkbox"> نشر الواجب الآن</label><button class="btn primary full-span" type="submit">حفظ الواجب</button></form></div></div>`);const form=document.getElementById('assignmentFormV63');form.addEventListener('submit',saveAssignmentV63);form.elements.deliveryMode.addEventListener('change',()=>refreshTargetGroupsV63(form));form.elements.grade.addEventListener('change',()=>refreshTargetGroupsV63(form));hydrateIcons();}
window.closeAssignmentEditorV63=function(){const modal=document.getElementById('assignmentEditorV63');if(modal)modal.hidden=true;};
window.openAssignmentEditorV63=function(id=''){const modal=document.getElementById('assignmentEditorV63'),form=document.getElementById('assignmentFormV63');if(!modal||!form)return;form.reset();const item=(adminData.assignments||[]).find(row=>String(row.id)===String(id));['id','title','deliveryMode','grade','dueDate','notes'].forEach(key=>form.elements[key].value=item?.[key]||(key==='deliveryMode'?'all':key==='grade'?'كل الصفوف':''));refreshTargetGroupsV63(form,item?.group||'كل المجموعات');form.elements.active.checked=item?item.active!==false:true;document.getElementById('assignmentTitleV63').textContent=item?`تعديل: ${item.title}`:'واجب جديد';modal.hidden=false;form.elements.title.focus();};
async function saveAssignmentV63(event){event.preventDefault();const form=event.currentTarget,values=Object.fromEntries(new FormData(form).entries()),file=form.file.files[0],existing=(adminData.assignments||[]).find(item=>String(item.id)===String(values.id)),before=existing?{...existing}:null,button=form.querySelector('[type=submit]');delete values.file;values.id=values.id||`as-${Date.now()}`;values.active=form.active.checked;values.updatedAt=new Date().toISOString();button.disabled=true;try{if(file){const uploaded=await window.MFCloud.uploadAttachment(file,'assignments');values.fileUrl=uploaded.url;values.fileName=file.name;}const index=adminData.assignments.findIndex(item=>String(item.id)===String(values.id));if(index>=0)adminData.assignments[index]={...adminData.assignments[index],...values};else adminData.assignments.push({...values,createdAt:new Date().toISOString()});await saveAdminDataNow();aToast(index>=0?'تم تعديل الواجب':'تم حفظ الواجب');closeAssignmentEditorV63();renderAssignmentsManagerV63();}catch(error){if(before){const index=adminData.assignments.findIndex(item=>String(item.id)===String(values.id));if(index>=0)adminData.assignments[index]=before;}else adminData.assignments=adminData.assignments.filter(item=>String(item.id)!==String(values.id));aToast(adminActionErrorMessage(error,'تعذر حفظ الواجب.'));}finally{button.disabled=false;}}
window.toggleAssignmentV63=async function(id){const item=(adminData.assignments||[]).find(row=>String(row.id)===String(id));if(!item)return;const before=item.active;item.active=item.active===false;try{await saveAdminDataNow();renderAssignmentsManagerV63();}catch(error){item.active=before;aToast(adminActionErrorMessage(error,'تعذر تحديث الواجب.'));}};
window.showAssignmentSubmissionsV63=function(id){const assignment=(adminData.assignments||[]).find(item=>String(item.id)===String(id)),rows=assignmentSubmissionsV63(id);document.getElementById('assignmentSubmissionsModal')?.remove();document.body.insertAdjacentHTML('beforeend',`<div class="admin-form-modal mobile-manager-modal" id="assignmentSubmissionsModal"><div class="admin-form-modal-card card"><div class="profile-top"><div><span class="kicker">تسليمات الواجب</span><h2>${safe(assignment?.title||'الواجب')}</h2></div><button class="small-btn danger" onclick="this.closest('.admin-form-modal').remove()">إغلاق</button></div><div class="admin-clean-list assignment-submission-list">${rows.map(row=>`<article class="payment-history-row"><div><b>${safe(row.studentName)}</b><small>${safe(row.studentCode)} · ${safe(row.status||'بانتظار المراجعة')}</small></div>${row.fileUrl?`<a class="small-btn" href="${safe(row.fileUrl)}" target="_blank" rel="noopener">فتح الملف</a>`:''}<button class="small-btn primary" onclick="reviewHomeworkV63('${safe(id)}','${safe(row.id)}','${safe(row.studentCode)}')">تصحيح</button></article>`).join('')||'<div class="empty-state"><h3>لا توجد تسليمات لهذا الواجب</h3></div>'}</div></div></div>`);};
window.reviewHomeworkV63=async function(assignmentId,id,studentCode){const student=(adminData.students||[]).find(item=>String(stCode(item))===String(studentCode)),record=(student?.homeworks||[]).find(item=>String(item.id)===String(id));if(!record)return;const score=prompt('الدرجة من 100',record.score??'' );if(score===null)return;if(score!==''&&(Number(score)<0||Number(score)>100))return aToast('اكتب درجة بين 0 و100');const teacherComment=prompt('ملاحظة المدرس',record.teacherComment||'')??(record.teacherComment||'');try{const patch=await window.MFCloud.reviewHomeworkSubmission(id,{status:'تمت المراجعة',approved:true,score,teacherComment});Object.assign(record,patch);aToast('تم حفظ تصحيح الواجب');showAssignmentSubmissionsV63(assignmentId);}catch(error){aToast(adminActionErrorMessage(error,'تعذر حفظ التصحيح.'));}};

function onlineContentRowV63(item){return `<article class="card admin-content-row mobile-manager-row online-manager-row"><span class="admin-content-icon" data-icon="external-link"></span><div class="manager-row-copy"><b>${safe(item.title||'محتوى')}</b><small>${safe(item.contentType||'تسجيل')} · ${safe(item.grade||'كل الصفوف')} · ${(item.access||'subscribers')==='subscribers'?'للمشتركين':'مجاني'} · ${safe(item.startAt?new Date(item.startAt).toLocaleString('ar-EG'):'بدون موعد')}</small></div><span class="badge manager-row-status ${item.active===false?'warn':'good'}">${item.active===false?'مسودة':'منشور'}</span><div class="mobile-manager-actions">${item.fileUrl||item.linkUrl?`<a class="small-btn ghost" href="${safe(item.fileUrl||item.linkUrl)}" target="_blank" rel="noopener">فتح</a>`:''}<button class="small-btn primary" onclick="openOnlineContentEditorV63('${safe(item.id)}')">تعديل</button><button class="small-btn ghost" onclick="toggleOnlineContentV63('${safe(item.id)}')">${item.active===false?'نشر':'إيقاف'}</button><button class="small-btn danger" onclick="deleteItem('materials','${safe(item.id)}')">حذف</button></div></article>`;}
function renderOnlineManagerV63(){fresh();const rows=(adminData.materials||[]).filter(item=>['upcoming','recording','file'].includes(item.contentType));content(`<div class="section-head mobile-manager-head"><div><span class="kicker"><span data-icon="external-link"></span> محاضرات الأونلاين</span><h2 class="section-title">المحاضرات والروابط والملفات</h2><p class="section-desc">أضف البث القادم أو التسجيل أو ملف PDF وحدد الصف وفترة الإتاحة.</p></div><button class="btn primary" onclick="openOnlineContentEditorV63()">+ محتوى أونلاين</button></div><div class="admin-clean-list mobile-manager-list">${rows.map(onlineContentRowV63).join('')||'<div class="card empty-state"><h3>لا يوجد محتوى أونلاين</h3></div>'}</div><div class="admin-form-modal mobile-manager-modal" id="onlineContentEditorV63" hidden><div class="admin-form-modal-card card"><div class="profile-top"><h2 id="onlineContentTitleV63">محتوى جديد</h2><button class="small-btn danger" type="button" onclick="closeOnlineContentEditorV63()">إغلاق</button></div><form id="onlineContentFormV63" class="admin-form-grid mobile-manager-form"><input type="hidden" name="id"><div class="field"><label>العنوان</label><input name="title" required></div><div class="field"><label>نوع المحتوى</label><select name="contentType"><option value="upcoming">محاضرة قادمة أو بث مباشر</option><option value="recording">تسجيل محاضرة</option><option value="file">ملف PDF أو صورة</option></select></div><div class="field"><label>الإتاحة</label><select name="access"><option value="subscribers">للمشتركين الذين تم دفعهم</option><option value="public">مجاني لكل طلاب الصف</option></select></div><div class="field"><label>الصف</label><select name="grade"><option>كل الصفوف</option>${GRADES.map(g=>`<option>${safe(g)}</option>`).join('')}</select></div><div class="field"><label>الترم</label><select name="term"><option>الترم الأول</option><option>الترم الثاني</option></select></div><div class="field"><label>الوحدة</label><input name="unit"></div><div class="field"><label>الفصل أو الدرس</label><input name="chapter"></div><div class="field"><label>موعد البدء</label><input name="startAt" type="datetime-local"></div><div class="field"><label>المدة بالدقائق</label><input name="duration" type="number" min="0"></div><div class="field full-span"><label>رابط البث أو Drive</label><input name="linkUrl" type="url" dir="ltr" placeholder="https://..."></div><div class="field full-span"><label>وصف مختصر</label><textarea name="desc"></textarea></div><label class="admin-file-drop full-span"><b>رفع PDF أو صورة بدل الرابط</b><input name="file" type="file" accept="application/pdf,image/*"></label><label class="option-card full-span"><input name="active" type="checkbox"> نشر المحتوى الآن</label><button class="btn primary full-span" type="submit">حفظ المحتوى</button></form></div></div>`);document.getElementById('onlineContentFormV63').addEventListener('submit',saveOnlineContentV63);hydrateIcons();}
window.closeOnlineContentEditorV63=function(){const modal=document.getElementById('onlineContentEditorV63');if(modal)modal.hidden=true;};
window.openOnlineContentEditorV63=function(id=''){
  const modal=document.getElementById('onlineContentEditorV63'),form=document.getElementById('onlineContentFormV63');
  if(!modal||!form)return;
  form.reset();
  const item=(adminData.materials||[]).find(row=>String(row.id)===String(id));
  const defaults={contentType:'recording',access:'subscribers',grade:'كل الصفوف',term:'الترم الأول'};
  ['id','title','contentType','access','grade','term','unit','chapter','startAt','duration','linkUrl','desc'].forEach(key=>{form.elements[key].value=item?.[key]??defaults[key]??'';});
  form.elements.active.checked=item?item.active!==false:true;
  document.getElementById('onlineContentTitleV63').textContent=item?`تعديل: ${item.title}`:'محتوى جديد';
  modal.hidden=false;form.elements.title.focus();
};
async function saveOnlineContentV63(event){event.preventDefault();const form=event.currentTarget,values=Object.fromEntries(new FormData(form).entries()),file=form.file.files[0],existing=(adminData.materials||[]).find(item=>String(item.id)===String(values.id)),before=existing?{...existing}:null,button=form.querySelector('[type=submit]');delete values.file;if(!values.linkUrl&&!file&&!existing?.fileUrl)return aToast('أضف رابطًا أو ارفع ملفًا');values.id=values.id||`online-${Date.now()}`;values.deliveryMode='online';values.active=form.active.checked;values.updatedAt=new Date().toISOString();button.disabled=true;try{if(file){const uploaded=await window.MFCloud.uploadAttachment(file,'online-content');values.fileUrl=uploaded.url;values.fileName=file.name;}const index=adminData.materials.findIndex(item=>String(item.id)===String(values.id));if(index>=0)adminData.materials[index]={...adminData.materials[index],...values};else adminData.materials.push({...values,createdAt:new Date().toISOString()});await saveAdminDataNow();aToast(index>=0?'تم تعديل المحتوى':'تم نشر المحتوى');closeOnlineContentEditorV63();renderOnlineManagerV63();}catch(error){if(before){const index=adminData.materials.findIndex(item=>String(item.id)===String(values.id));if(index>=0)adminData.materials[index]=before;}else adminData.materials=adminData.materials.filter(item=>String(item.id)!==String(values.id));aToast(adminActionErrorMessage(error,'تعذر حفظ المحتوى.'));}finally{button.disabled=false;}}
window.toggleOnlineContentV63=async function(id){const item=(adminData.materials||[]).find(row=>String(row.id)===String(id));if(!item)return;const before=item.active;item.active=item.active===false;try{await saveAdminDataNow();renderOnlineManagerV63();}catch(error){item.active=before;aToast(adminActionErrorMessage(error,'تعذر تحديث المحتوى.'));}};

function renderSection(){({overview:renderOverview,students:renderStudentsUnifiedV62,bookings:renderBookings,schedules:renderSchedulesUnifiedV62,attendance:renderAttendanceUnifiedV62,payments:renderPaymentsUnified,exams:renderExamsManagerV63,onlineContent:renderOnlineManagerV63,materials:renderMaterialsProfessionalV62,questionBank:renderQuestionBankProfessionalV62,assignments:renderAssignmentsManagerV63,reviews:renderSaadReviews,reports:renderReports,backup:renderBackup,settings:renderSettings}[currentSection]||renderOverview)();}
function exportCSV(name, rows){const csv=rows.map(r=>r.map(v=>`"${String(v??'').replace(/"/g,'""')}"`).join(',')).join('\n'); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob(['\ufeff'+csv],{type:'text/csv'})); a.download=name; a.click();}
window.exportBookingsCSV=function(){exportCSV('bookings.csv',[['code','name','grade','month','group','parentPhone','status'],...adminData.bookings.map(b=>[b.code,b.name,b.grade,b.month,b.group,b.parentPhone,b.status])]);};

function initAdmin(){const requested=new URLSearchParams(location.search).get('section');if(adminSections.some(([id])=>id===requested))currentSection=requested;setupTheme(); hydrateIcons(); adminLogin(); tryRestoreSession();}
document.addEventListener('DOMContentLoaded',initAdmin);
